# apply-proxy-mode.ps1
# In-app proxy mode: runs the olcRTC core in the app process,
# exposes a local SOCKS5 and runs a built-in connectivity test.
# Run from the repo root (C:\OLCVPN\OLCVPN-ios-unsigned):
#   powershell -ExecutionPolicy Bypass -File .\apply-proxy-mode.ps1
$ErrorActionPreference = 'Stop'
$root = (Get-Location).Path
if (-not (Test-Path (Join-Path $root 'project.yml'))) {
  Write-Error 'project.yml not found. Run this script from the OLCVPN repo root.'
  exit 1
}
function Write-FileB64($rel, $b64) {
  $path = Join-Path $root $rel
  $dir  = Split-Path $path -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [System.Convert]::FromBase64String($b64)
  [System.IO.File]::WriteAllBytes($path, $bytes)
  Write-Host ('  wrote: ' + $rel)
}
function Remove-FileRel($rel) {
  $path = Join-Path $root $rel
  if (Test-Path $path) { Remove-Item -Force $path; Write-Host ('  removed: ' + $rel) }
}
Write-Host 'Writing files...'
Write-FileB64 'Shared/OLCCore.swift' ''
Write-FileB64 'Shared/CoreLogCapture.swift' ''
Write-FileB64 'Shared/CoreLogWriter.swift' ''
Write-FileB64 'App/VPN/ProxyManager.swift' ''
Write-FileB64 'App/Views/ProxyTestView.swift' ''
Write-FileB64 'App/OLCVPNApp.swift' ''
Write-Host 'Removing moved/old files...'
Remove-FileRel 'OLCTunnel/OLCCore.swift'
Write-Host 'Committing and pushing...'
git add -A
git commit -m "feat(proxy): pipe core Go log via MobileSetLogWriter into in-app Proxy log"
git push
Write-Host ''
Write-Host 'Done. Watch the build: https://github.com/lucudar/OLCVPN/actions'
